                         </div>
                     </div>

                     <p className="text-slate-600 dark:text-slate-400 mb-8 max-w-lg">
                        {todayCompleted === 10 
                            ? "Crushed it today! Consistency is the key to greatness." 
                            : isReadOnly ? "View the progress for today." : "Keep pushing. Every checked box is a step towards a better you."}
                     </p>

                     <button 
                        onClick={() => onSelectDate(format(new Date(), 'yyyy-MM-dd'))}
                        className={`
                            w-full sm:w-auto px-8 py-4 rounded-xl font-bold text-white shadow-lg shadow-indigo-500/20 transition-all transform hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-2
                            ${todayCompleted === 10 ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}
                        `}
                     >
                        {todayCompleted === 10 || isReadOnly ? <CheckIcon className="w-5 h-5"/> : <PencilIcon className="w-5 h-5"/>}
                        {todayCompleted === 10 || isReadOnly ? 'View Report' : 'Log Habits'}
                     </button>
                 </div>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                 <StatCard label="Current Streak" value={`${stats.streak} Days`} icon={<FireIcon className="w-6 h-6"/>} colorClass="bg-orange-500" textColorClass="text-orange-600 dark:text-orange-400" />
                 <StatCard label="Perfect Days" value={stats.perfectDays} icon={<CheckIcon className="w-6 h-6"/>} colorClass="bg-green-500" textColorClass="text-green-600 dark:text-green-400" />
                 <StatCard label="Total Habits" value={stats.totalHabitsCompleted} icon={<ListIcon className="w-6 h-6"/>} colorClass="bg-blue-500" textColorClass="text-blue-600 dark:text-blue-400" />
                 <StatCard label="Consistency" value={`${stats.totalLoggedDays > 0 ? Math.round((stats.totalHabitsCompleted / (stats.totalLoggedDays * 10)) * 100) : 0}%`} icon={<ChartBarIcon className="w-6 h-6"/>} colorClass="bg-purple-500" textColorClass="text-purple-600 dark:text-purple-400" />
             </div>
        </div>
    );
};

const CalendarView: React.FC<{
    getDayChecks: (d: string) => boolean[],
    onSelectDate: (d: string) => void,
    habitNames: string[],
    onToggleHabit: (d: string, i: number) => void,
    isReadOnly: boolean
}> = ({ getDayChecks, onSelectDate, habitNames, onToggleHabit, isReadOnly }) => {
    const [currentDate, setCurrentDate] = useState(new Date());
    const [calendarView, setCalendarView] = useState<'year' | 'month' | 'week'>('month');

    const handlePrev = () => {
        if (calendarView === 'year') setCurrentDate(subYears(currentDate, 1));
        if (calendarView === 'month') setCurrentDate(subMonths(currentDate, 1));
        if (calendarView === 'week') setCurrentDate(subWeeks(currentDate, 1));
    };
    const handleNext = () => {
        if (calendarView === 'year') setCurrentDate(addYears(currentDate, 1));
        if (calendarView === 'month') setCurrentDate(addMonths(currentDate, 1));
        if (calendarView === 'week') setCurrentDate(addWeeks(currentDate, 1));
    };
    const handleToday = () => setCurrentDate(new Date());

    const daysInMonth = eachDayOfInterval({ 
        start: startOfWeek(startOfMonth(currentDate)), 
        end: endOfWeek(endOfMonth(currentDate)) 
    });

    return (
        <div className="space-y-6 animate-fade-in pb-10" key={habitNames.join(',')}>
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl w-full sm:w-auto">
                    {(['week', 'month', 'year'] as const).map((v) => (
                        <button
                            key={v}
                            onClick={() => setCalendarView(v)}
                            className={`flex-1 sm:flex-none px-4 py-2 text-sm font-bold rounded-lg transition-all capitalize ${
                                calendarView === v
                                ? 'bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 shadow-sm'
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
                            }`}
                        >
                            {v}
                        </button>
                    ))}
                </div>

                <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                    <h2 className="text-lg font-bold text-slate-900 dark:text-white sm:w-48 text-center sm:text-right">
                        {calendarView === 'year' && format(currentDate, 'yyyy')}
                        {calendarView === 'month' && format(currentDate, 'MMMM yyyy')}
                        {calendarView === 'week' && `Week of ${format(startOfWeek(currentDate), 'MMM d')}`}
