                                            </span>
                                            {count === 10 && <div className="text-green-500"><CheckIcon className="w-3 h-3 sm:w-4 sm:h-4"/></div>}
                                        </div>
                                        <div className={`hidden sm:block relative z-10 text-[9px] font-bold px-1.5 py-0.5 rounded-md truncate w-full text-center my-1 ${getMessageStyle(count)}`}>
                                            {message}
                                        </div>
                                        <div className="w-full space-y-1 mt-auto relative z-10">
                                            <div className="w-full bg-slate-100 dark:bg-slate-700 h-1 sm:h-1.5 rounded-full overflow-hidden">
                                                <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                            </div>
                                            <div className="hidden sm:block text-[10px] font-bold text-slate-400 text-right">{count}/10</div>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </>
                )}

                {calendarView === 'week' && (
                    <div className="overflow-x-auto relative">
                        <div className="min-w-[800px]">
                            <div className="grid grid-cols-[150px_repeat(7,1fr)] sm:grid-cols-[200px_repeat(7,1fr)] border-b border-slate-200 dark:border-slate-700">
                                <div className="sticky left-0 z-20 p-4 font-bold text-slate-400 uppercase text-xs tracking-wider flex items-center bg-slate-50 dark:bg-slate-900 border-r border-slate-200 dark:border-slate-700 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">Habit</div>
                                {eachDayOfInterval({
                                    start: startOfWeek(currentDate),
                                    end: endOfWeek(currentDate)
                                }).map(day => {
                                    const dStr = format(day, 'yyyy-MM-dd');
                                    const count = getDayChecks(dStr).filter(Boolean).length;
                                    const isPastDate = isBefore(day, startOfDay(new Date()));

                                    return (
                                        <button 
                                            key={day.toString()} 
                                            onClick={() => onSelectDate(dStr)}
                                            className={`p-2 sm:p-4 text-center border-l border-slate-100 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-800/80 transition-colors group relative overflow-hidden ${isToday(day) ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}`}
                                        >
                                            {isPastDate && count === 0 && (
                                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                                    <SpiderWebIcon className="w-10 h-10 sm:w-16 sm:h-16 text-red-900/30 dark:text-red-500/30 animate-pulse" />
                                                </div>
                                            )}
                                            <div className="relative z-10">
                                                <div className="text-[10px] sm:text-xs font-bold text-slate-500 uppercase group-hover:text-indigo-600 dark:group-hover:text-indigo-400">{format(day, 'EEE')}</div>
                                                <div className={`text-base sm:text-lg font-bold mt-1 group-hover:scale-110 transition-transform ${isToday(day) ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{format(day, 'd')}</div>
                                                {!isReadOnly && <div className="text-[10px] text-slate-400 mt-1 opacity-0 group-hover:opacity-100">Edit</div>}
