                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

const ReportsView: React.FC<{ logs: HabitLog, getDayChecks: (d: string) => boolean[], onSelectDate: (d: string) => void, habitNames: string[], dailyConfig: Record<string, string[]> }> = ({ logs, getDayChecks, onSelectDate, habitNames, dailyConfig }) => {
    const [viewMode, setViewMode] = useState<'analytics' | 'history'>('analytics');

    // Stats for Analytics
    const { pieData, barData, totalDays, monthlyData } = useMemo(() => {
        const scoreDist = [0, 0, 0, 0]; // 0: Inactive, 1: Average, 2: Good, 3: Perfect
        const habitCounts: Record<string, number> = {};
        let total = 0;
        const monthMap: Record<string, { total: number; count: number }> = {};

        Object.entries(logs).forEach(([dateStr, val]) => {
            const checks = val as boolean[];
            if (!checks || checks.length === 0) return;
            total++;
            const score = checks.filter(Boolean).length;

            if (score === 10) scoreDist[3]++;
            else if (score >= 6) scoreDist[2]++;
            else if (score >= 3) scoreDist[1]++;
            else scoreDist[0]++;

            const currentDayNames = dailyConfig[dateStr] || habitNames;
            checks.forEach((c, i) => {
                if (c) {
                    const name = currentDayNames[i] || `Habit ${i+1}`;
                    habitCounts[name] = (habitCounts[name] || 0) + 1;
                }
            });

            const dateObj = parseISO(dateStr);
            const monthSortKey = format(dateObj, 'yyyy-MM');

            if (!monthMap[monthSortKey]) monthMap[monthSortKey] = { total: 0, count: 0 };
            monthMap[monthSortKey].total += score;
            monthMap[monthSortKey].count += 1;
        });

        const pie = [
            { label: 'Perfect (10)', value: scoreDist[3], color: '#10b981' }, 
            { label: 'Good (6-9)', value: scoreDist[2], color: '#3b82f6' }, 
            { label: 'Average (3-5)', value: scoreDist[1], color: '#f97316' }, 
            { label: 'Poor (0-2)', value: scoreDist[0], color: '#ef4444' }, 
        ].filter(d => d.value > 0);

        const bar = Object.entries(habitCounts).map(([name, count], i) => ({
            label: name,
            value: count,
            percentage: total > 0 ? Math.round((count / total) * 100) : 0,
            color: VIBRANT_COLORS[i % VIBRANT_COLORS.length]
        })).sort((a, b) => b.value - a.value);

        const monthly = Object.entries(monthMap)
            .sort(([keyA], [keyB]) => keyA.localeCompare(keyB)) 
            .map(([sortKey, data]) => {
                const label = format(parse(sortKey, 'yyyy-MM', new Date()), 'MMM yyyy');
                return {
                    label,
                    value: Math.round((data.total / data.count) * 10) / 10,
                    color: '#6366f1'
                };
            })
            .slice(-12);

        return { pieData: pie, barData: bar, totalDays: total, monthlyData: monthly };
    }, [logs, habitNames, dailyConfig]);

    const sortedDates = Object.keys(logs || {}).sort().reverse();

    return (
        <div className="space-y-6 animate-fade-in pb-10" key={habitNames.join(',')}>
            <div className="flex items-center justify-between gap-4 mb-4">
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Reports & Analytics</h2>
                <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg">
                    <button onClick={() => setViewMode('analytics')} className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'analytics' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'}`}>Charts</button>
                    <button onClick={() => setViewMode('history')} className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'history' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'}`}>History</button>
                </div>
            </div>

            {viewMode === 'analytics' && (
                <>
                <YearlyHeatmap logs={logs} />
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                        <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-indigo-100 dark:bg-indigo-900/30 rounded-md text-indigo-600 dark:text-indigo-400"><PieChartIcon className="w-4 h-4"/></div> Consistency Breakdown
                        </h3>
                        <DonutChart data={pieData} total={totalDays} />
                    </div>
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                         <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-emerald-100 dark:bg-emerald-900/30 rounded-md text-emerald-600 dark:text-emerald-400"><ListIcon className="w-4 h-4"/></div> Habit Performance
                        </h3>
                        <HorizontalBarChart data={barData} />
                    </div>
                    <div className="md:col-span-2 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                         <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-purple-100 dark:bg-purple-900/30 rounded-md text-purple-600 dark:text-purple-400"><ChartBarIcon className="w-4 h-4"/></div> Monthly Average Score
                        </h3>
                        {monthlyData.length > 0 ? (
                            <VerticalBarGraph data={monthlyData} />
                        ) : (
                            <div className="h-32 flex items-center justify-center text-slate-400 text-sm">Insufficient data for trends</div>
                        )}
                    </div>
                </div>
                </>
            )}

            {viewMode === 'history' && (
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                    <div className="divide-y divide-slate-100 dark:divide-slate-700">
                    {sortedDates.length === 0 && (
                        <div className="p-12 text-center text-slate-500 dark:text-slate-400">No data recorded yet.</div>
                    )}
                    {sortedDates.map(date => {
                        const count = getDayChecks(date).filter(Boolean).length;
                        return (
                            <div key={date} onClick={() => onSelectDate(date)} className="p-4 sm:p-5 hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors flex items-center justify-between group">
                                <div className="flex items-center gap-4">
                                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg text-white shadow-sm ${getScoreColor(count)}`}>
                                        {count}
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-900 dark:text-white">{format(parseISO(date), 'MMMM do, yyyy')}</p>
                                        <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wide">{format(parseISO(date), 'EEEE')}</p>
                                    </div>
                                </div>
                                <ChevronDownIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" />
                            </div>
                        );
                    })}
                    </div>
                </div>
            )}
        </div>
    );
};

const SettingsView: React.FC<{
    habitNames: string[],
    setHabitNames: (newNames: string[]) => void,
    onResetLogs: () => void
}> = ({ habitNames, setHabitNames, onResetLogs }) => (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in pb-10">
        <div className="bg-white dark:bg-slate-800 p-6 sm:p-8 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
            <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-lg text-indigo-600 dark:text-indigo-400"><PencilIcon className="w-5 h-5" /></div>
                Edit Default Habits
            </h3>
            <div className="space-y-4">
                {habitNames.map((name, idx) => (
                    <div key={idx} className="group">
                        <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1 ml-1">Habit {idx + 1}</label>
                        <input 
                            type="text" 
                            value={name} 
                            onChange={(e) => {
                                const newNames = [...habitNames];
                                newNames[idx] = e.target.value;
                                setHabitNames(newNames);
                            }}
                            className="modern-input w-full font-medium"
                            placeholder={`Enter habit ${idx + 1}`}
                        />
                    </div>
                ))}
            </div>
        </div>

        <div className="bg-red-50 dark:bg-red-900/10 p-6 sm:p-8 rounded-2xl border border-red-100 dark:border-red-900/30">
            <h3 className="text-lg font-bold text-red-700 dark:text-red-400 mb-2">Danger Zone</h3>
            <p className="text-sm text-red-600/70 dark:text-red-300/70 mb-6">Clear all habit history. This cannot be undone.</p>
            <button 
                onClick={onResetLogs}
                className="px-6 py-3 bg-white border border-red-200 text-red-600 hover:bg-red-50 text-sm font-bold rounded-xl transition-colors shadow-sm"
            >
                Reset All Data
            </button>
        </div>
    </div>
);

// --- Main Page Component ---

const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, targetUser, onClose }) => {
    const activeUser = targetUser || user;
    // Admins can edit anyone's data. Normal users can only edit their own.
    const isReadOnly = targetUser && targetUser.id !== user.id && user.role !== 'admin';
    const { addNotification } = useNotificationState();

    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');
    const [habitNames, setHabitNamesState] = useState<string[]>(DEFAULT_HABITS);
    const [dailyConfig, setDailyConfigState] = useState<Record<string, string[]>>({});
    const [logs, setLogsState] = useState<HabitLog>({});
    const [selectedDate, setSelectedDate] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isRealtimeConnected, setIsRealtimeConnected] = useState(false);

    // Fetch data on mount
    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const settings = await getHabitSettings(activeUser.id);
                setHabitNamesState(settings.habits);
                setDailyConfigState(settings.daily_config);

                const logsData = await getHabitLogs(activeUser.id);
                const logMap: HabitLog = {};
                logsData.forEach(l => { logMap[l.date] = l.checks; });
                setLogsState(logMap);
            } catch (err) {
                console.error("Failed to load habits", err);
                addNotification({ title: 'Error', message: 'Failed to load habit data.', type: 'error' });
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, [activeUser.id, addNotification]);

    // Realtime Sync
    useEffect(() => {
        const supabase = getSupabase();
        if (!supabase || isUsingMockData()) return;

        // Sync Settings
        const settingsChannel = supabase.channel(`public:habit_settings:${activeUser.id}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'habit_settings', filter: `user_id=eq.${activeUser.id}` }, (payload) => {
                const newSettings = payload.new as any;
                if (newSettings) {
                    setHabitNamesState(newSettings.habits || DEFAULT_HABITS);
                    setDailyConfigState(newSettings.daily_config || {});
                }
            })
            .subscribe((status) => {
                 if (status === 'SUBSCRIBED') setIsRealtimeConnected(true);
            });

        // Sync Logs
        const logsChannel = supabase.channel(`public:habit_logs:${activeUser.id}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'habit_logs', filter: `user_id=eq.${activeUser.id}` }, (payload) => {
                const newLog = payload.new as any;
                if (newLog) {
                    setLogsState(prev => ({ ...prev, [newLog.date]: newLog.checks }));
                }
            })
            .subscribe();

        return () => { 
            supabase.removeChannel(settingsChannel);
            supabase.removeChannel(logsChannel);
            setIsRealtimeConnected(false);
        };
    }, [activeUser.id]);


    const today = format(new Date(), 'yyyy-MM-dd');
    const todayChecks = logs[today] || Array(MAX_HABITS).fill(false);
    const todayCompleted = todayChecks.filter(Boolean).length;

    const getHabitsForDate = (date: string) => {
        return dailyConfig[date] || habitNames;
    };

    const getDayChecks = (date: string) => {
        return logs[date] || Array(MAX_HABITS).fill(false);
    };

    // DB Update Wrappers
    const updateHabitSettings = async (newHabits: string[], newDailyConfig: Record<string, string[]>) => {
        setHabitNamesState(newHabits);
        setDailyConfigState(newDailyConfig);
        try {
            await saveHabitSettings(activeUser.id, newHabits, newDailyConfig);
        } catch (e) {
            console.error("Failed to save habit settings", e);
        }
    };

    const updateHabitLog = async (date: string, checks: boolean[]) => {
        setLogsState(prev => ({ ...prev, [date]: checks }));
        try {
            await saveHabitLog(activeUser.id, date, checks);
        } catch (e) {
            console.error("Failed to save log", e);
        }
    };

    const handleToggleHabit = (date: string, index: number) => {
        if (isReadOnly) return;
        const currentChecks = getDayChecks(date);
        const newChecks = [...currentChecks];
        newChecks[index] = !newChecks[index];
        updateHabitLog(date, newChecks);
    };

    const handleRenameHabit = (index: number, newName: string) => {
        if (!selectedDate || isReadOnly) return;

        const newNames = [...habitNames];
        newNames[index] = newName;

        let newDailyConfig = { ...dailyConfig };
        if (dailyConfig[selectedDate]) {
            const currentList = [...dailyConfig[selectedDate]];
            currentList[index] = newName;
            newDailyConfig[selectedDate] = currentList;
        }

        updateHabitSettings(newNames, newDailyConfig);
    };

    const handleCustomizeDay = () => {
        if (!selectedDate || isReadOnly) return;
        const newDailyConfig = { ...dailyConfig, [selectedDate]: [...habitNames] };
        updateHabitSettings(habitNames, newDailyConfig);
    };

    const handleResetDayHabits = () => {
        if (!selectedDate || isReadOnly) return;
        const newDailyConfig = { ...dailyConfig };
        delete newDailyConfig[selectedDate];
        updateHabitSettings(habitNames, newDailyConfig);
    };

    const handleResetLogs = async () => {
        if(window.confirm("Are you sure you want to delete all habit logs? This action is irreversible.")) {
            setLogsState({});
            try {
                await resetHabitLogs(activeUser.id);
                addNotification({ title: 'Reset Complete', message: 'All habit logs cleared.', type: 'success' });
            } catch (e) {
                addNotification({ title: 'Error', message: 'Failed to reset logs.', type: 'error' });
            }
        }
    };

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <ChartBarIcon className="w-5 h-5"/> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5"/> },
        { id: 'reports', label: 'Reports', icon: <ListIcon className="w-5 h-5"/> },
        // Hide settings for ReadOnly viewers
        ...(isReadOnly ? [] : [{ id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5"/> }]),
    ];

    // Stats Logic (Local calculation based on fetched logs)
    const stats = useMemo(() => {
        const entries = Object.entries(logs).filter(([_, checks]) => Array.isArray(checks) && checks.some(Boolean));
        const totalLoggedDays = entries.length;
        const totalHabitsCompleted = entries.reduce((acc, [_, checks]) => acc + checks.filter(Boolean).length, 0);
        const perfectDays = entries.filter(([_, checks]) => checks.filter(Boolean).length === MAX_HABITS).length;

        // Calculate Streak
        let streak = 0;
        let checkDate = new Date();
        const checkDateStr = format(checkDate, 'yyyy-MM-dd');
        const todayLog = logs[checkDateStr];

        if (!todayLog || todayLog.filter(Boolean).length === 0) {
             checkDate = subDays(checkDate, 1);
        }

        for (let i = 0; i < 365; i++) {
             const dStr = format(checkDate, 'yyyy-MM-dd');
             const dayLog = logs[dStr];
             if (dayLog && dayLog.some(Boolean)) {
                 streak++;
                 checkDate = subDays(checkDate, 1);
             } else {
                 break;
             }
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs]);

    if (isLoading) {
        return <div className="h-full w-full flex items-center justify-center"><SpinnerIcon className="w-10 h-10 text-emerald-500 animate-spin"/></div>;
    }

    return (
        <div className="h-full w-full flex flex-col md:flex-row bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            <HabitModal 
                isOpen={!!selectedDate} 
                date={selectedDate || today} 
                onClose={() => setSelectedDate(null)} 
                habits={selectedDate ? getHabitsForDate(selectedDate) : habitNames}
                checks={selectedDate ? getDayChecks(selectedDate) : []}
                onToggle={(idx) => selectedDate && handleToggleHabit(selectedDate, idx)}
                isReadOnly={isReadOnly}
                onRename={(idx, val) => selectedDate && handleRenameHabit(idx, val)}
                onReset={() => selectedDate && handleResetDayHabits()}
                onCustomize={() => selectedDate && handleCustomizeDay()}
                isCustomized={!!selectedDate && !!dailyConfig[selectedDate]}
            />

            {/* Desktop Sidebar */}
            <aside className="hidden md:flex flex-col w-64 lg:w-72 border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 flex-shrink-0">
                <div className="p-6 border-b border-slate-100 dark:border-slate-800">
                    <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg text-emerald-600 dark:text-emerald-400">
                            <ClockIcon className="w-6 h-6" />
                        </div>
                        <h1 className="font-extrabold text-xl tracking-tight text-slate-900 dark:text-white">Consistency</h1>
                    </div>
                    <div className="flex items-center gap-2 pl-1">
                        {isRealtimeConnected && (
                            <span className="relative flex h-2 w-2">
                              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                              <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                            </span>
                        )}
                        <p className="text-xs text-slate-400">
                            {isReadOnly ? `${activeUser.name}'s Habits` : 'Build better habits.'}
                        </p>
                    </div>
                </div>

                <nav className="p-4 space-y-1 flex-1 overflow-y-auto">
                    {navItems.map(item => (
                        <button
                            key={item.id}
                            onClick={() => setView(item.id as any)}
                            className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-sm font-bold transition-all ${
                                view === item.id 
                                ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                                : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                            }`}
                        >
                            {item.icon}
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-100 dark:border-slate-800">
                    <div onClick={onClose} className="flex items-center gap-3 px-4 py-3 text-sm font-bold text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 cursor-pointer transition-colors rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800">
                        <ArrowLeftIcon className="w-5 h-5" /> Back to OS
                    </div>
                </div>
            </aside>

            {/* Mobile Top Bar */}
            <div className="md:hidden flex items-center justify-between p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 sticky top-0 z-20">
                 <div className="flex items-center gap-2 font-bold text-slate-900 dark:text-white text-lg">
                     <ClockIcon className="w-6 h-6 text-emerald-500" /> Consistency
                 </div>
                 <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-100 rounded-full">
                     <XCircleIcon className="w-6 h-6" />
                 </button>
            </div>

            {/* Main Content Area */}
            <main className="flex-1 overflow-y-auto p-4 sm:p-8 bg-slate-50 dark:bg-slate-950/50 relative pb-24 md:pb-8 scroll-smooth">
                <div className="max-w-6xl mx-auto h-full flex flex-col">
                    <header className="mb-8 hidden md:block">
                        <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white capitalize tracking-tight">{view}</h2>
                        <p className="text-slate-500 dark:text-slate-400 mt-2 text-lg">
                            {view === 'dashboard' && "Track your daily discipline."}
                            {view === 'calendar' && "Visualize your consistency over time."}
                            {view === 'reports' && "Detailed history of your habits."}
                            {view === 'settings' && "Configure your 10 core habits."}
                        </p>
                    </header>

                    <div className="flex-1 min-h-0">
                        {view === 'dashboard' && (
                            <DashboardView 
                                todayCompleted={todayCompleted} 
                                stats={stats} 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate}
                                isReadOnly={isReadOnly}
                            />
                        )}
                        {view === 'calendar' && (
                            <CalendarView 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate} 
                                habitNames={habitNames}
                                onToggleHabit={handleToggleHabit}
                                isReadOnly={isReadOnly}
                            />
                        )}
                        {view === 'reports' && (
                            <ReportsView 
                                logs={logs} 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate}
                                habitNames={habitNames}
                                dailyConfig={dailyConfig}
                            />
                        )}
                        {view === 'settings' && !isReadOnly && (
                            <SettingsView 
                                habitNames={habitNames} 
                                setHabitNames={(names) => updateHabitSettings(names, dailyConfig)}
                                onResetLogs={handleResetLogs} 
                            />
                        )}
                    </div>
                </div>
            </main>

            {/* Mobile Bottom Navigation */}
            <nav className="md:hidden absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <div className={`grid ${isReadOnly ? 'grid-cols-3' : 'grid-cols-4'} h-16`}>
                    {navItems.map(item => (
                        <BottomNavButton 
                            key={item.id}
                            icon={item.icon}
                            label={item.label}
                            isActive={view === item.id}
                            onClick={() => setView(item.id as any)}
                        />
                    ))}
                </div>
            </nav>
        </div>
    );
};

export default HabitTrackerPage;
